import json
from datetime import datetime

with open(locals()['var_function-call-8126399227036074897'], 'r') as f:
    data = json.load(f)

start_date = datetime(2022, 4, 1)
end_date = datetime(2023, 3, 31)

def clean_id(val):
    if not val or val == 'None':
        return None
    val = str(val).strip()
    if val.startswith('#'):
        return val[1:]
    return val

assignment_counts = {}
transfer_counts = {}

for r in data:
    if r.get('field__c') != 'Owner Assignment':
        continue

    c_date_str = r.get('createddate')
    try:
        dt = datetime.strptime(c_date_str[:10], "%Y-%m-%d")
        if not (start_date <= dt <= end_date):
            continue
    except:
        continue

    ov = clean_id(r.get('oldvalue__c'))
    nv = clean_id(r.get('newvalue__c'))

    # Count transfers out
    if ov:
        transfer_counts[ov] = transfer_counts.get(ov, 0) + 1
        # Also ensure ov is in assignment_counts (if they transferred, they must have been assigned, though maybe not in this period)
        # But for sorting, we rely on assignment counts in this period.
        if ov not in assignment_counts:
            assignment_counts[ov] = 0

    # Count assignments in
    if nv:
        assignment_counts[nv] = assignment_counts.get(nv, 0) + 1
        # Ensure nv in transfer_counts
        if nv not in transfer_counts:
            transfer_counts[nv] = 0

# Filter for those with 0 transfers
candidates = []
for agent, t_count in transfer_counts.items():
    if t_count == 0:
        candidates.append({
            "id": agent,
            "assignments": assignment_counts.get(agent, 0)
        })

# Sort candidates by assignments (desc)
sorted_candidates = sorted(candidates, key=lambda x: x['assignments'], reverse=True)

print("__RESULT__:")
print(json.dumps(sorted_candidates[:10]))

